import { Link } from "react-router-dom";
import { useNavigate } from "react-router-dom";
import { api, clearAuthToken, getAuthToken, isSignupComplete } from "../api";

export default function Navbar() {
  const navigate = useNavigate();
  const isLoggedIn = Boolean(getAuthToken());

  const handleLogout = async () => {
    try {
      await api.post("/auth/logout/");
    } catch (err) {
      // Ignore server logout failures and clear client auth state anyway.
    }
    clearAuthToken();
    navigate("/login");
  };

  return (
    <nav className="navbar">
      <div className="navbar-left">
        <Link to="/" className="navbar-logo">💊 MedCompare</Link>
        {!isLoggedIn && (
          <>
            <Link to="/">Home</Link>
            <Link to="/search">Search</Link>
            <Link to="/cart">🛒 Cart</Link>
          </>
        )}
      </div>
      
      <div className="navbar-right">
        {!isLoggedIn && (
          <>
            <Link to="/profile">👤 Profile</Link>
            <Link to="/orders">📦 Orders</Link>
            {getAuthToken() && <Link to="/shop-register">🏪 Store</Link>}
            {getAuthToken() && <Link to="/my-medicines">💊 My Medicines</Link>}
          </>
        )}
        
        {!isLoggedIn && (
          <>
            <Link to={isSignupComplete() ? "/login" : "/signup"} className="btn-small">Sign In</Link>
            <Link to="/signup" className="btn-small btn-primary">Sign Up</Link>
          </>
        )}
        
        {!isLoggedIn && (
          <button className="btn-logout" onClick={handleLogout}>
            Logout
          </button>
        )}
      </div>
    </nav>
  );
}
